      // The use of inline closures is to circumvent an issue where the compiler
      // allocates stack space for every case branch when no optimizations are
      // enabled. https://github.com/apple/swift-protobuf/issues/1034
      switch fieldNumber {
      case 1: try { try decoder.decodeSingularStringField(value: &self.markdown) }()
      case 2: try { try decoder.decodeSingularMessageField(value: &self._capturedAt) }()
      default: break
      }
    }
  }

  public func traverse<V: SwiftProtobuf.Visitor>(visitor: inout V) throws {
    // The use of inline closures is to circumvent an issue where the compiler
    // allocates stack space for every if/case branch local when no optimizations
    // are enabled. https://github.com/apple/swift-protobuf/issues/1034 and
    // https://github.com/apple/swift-protobuf/issues/1182
    if !self.markdown.isEmpty {
      try visitor.visitSingularStringField(value: self.markdown, fieldNumber: 1)
    }
    try { if let v = self._capturedAt {
      try visitor.visitSingularMessageField(value: v, fieldNumber: 2)
    } }()
    try unknownFields.traverse(visitor: &visitor)
  }

  public static func ==(lhs: FleetDiagnosticsResponse, rhs: FleetDiagnosticsResponse) -> Bool {
    if lhs.markdown != rhs.markdown {return false}
    if lhs._capturedAt != rhs._capturedAt {return false}
    if lhs.unknownFields != rhs.unknownFields {return false}
    return true
  }
}
